/**
 * input type 반환 함수
 *
 * @param {string} attribute type value
 *
 * @return {string} input type
 *
 * @private
 * @memberOf BxInput
 */
function _getInputClassTypeName(type = ''){

    if (!_.isString(type)){
        CONSOLE.prop.throw(Base, 'type', 'type');
    }

    let ret = 'input';

    if (type === 'checkbox' || type === 'radio') ret = type;

    return ret;
}

/**
 * component option 필수 값 세팅 후 반환하는 함수
 *
 * @param {object} 기본값 옵션 객체
 *
 * @return {object} component opts
 *
 * @private
 * @memberOf BxInput
 */
function _setMandatoryOPTS(opts = {}){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw(Base, 'opts', 'type');
    }

    let attr = opts.attr;
    let type = attr.type;

    let id = _.trim(attr.id);

    if (!id) {
        attr.id = UTIL.uniqueId(this.inputSelector.bxInput);
    }

    return opts;
}


/**
 * 유효한 소수점 반환 함수
 *
 * @param {value} 체크할 값
 *
 * @return {array} 체크된 정수 및 소수 배열
 *
 * @private
 * @memberOf BxInput
 */
function _getValidDecimal(value = ''){

    if (!_.isString(value)){
        CONSOLE.prop.throw(Base, 'value', 'type');
    }

    let splitValue = [];
    let integer = '';
    let decimal = '';

    let dotPtn = /\./gi;
    let notNumericPtn = /\D/g;

    if (value.match(dotPtn) && value.match(dotPtn).length > 1){
        value = value.replace(notNumericPtn, '');
    }

    if (value.match(dotPtn) && value.match(dotPtn).length === 1){
        splitValue = value.split('.');
    }
    else{
        splitValue[0] = value;
    }

    //integer
    integer = splitValue[0].replace(/(^0+)/, '');

    if (integer.length === 0) integer = '0';

    //decimal
    if (!_.isUndefined(splitValue[1])) decimal = '.' + splitValue[1];

    return {
        "integer": integer,
        "decimal": decimal
    };
}

module.exports = Base;